316	/// Format one help row: a `label` and one-or-more wrapped description lines,
317	/// aligned to a common description column. If the label is too wide, the
318	/// description starts on the next line.
319	fn help_row(label: &str, desc: &[&str]) -> String {
320	    const COL: usize = 24; // label column width; description starts after it
321	    let mut out = String::new();
322	    if label.len() <= COL {
323	        out.push_str(&format!("  {label:<COL$}{}\n", desc[0]));
324	    } else {
325	        out.push_str(&format!("  {label}\n"));
326	        out.push_str(&format!("  {:<COL$}{}\n", "", desc[0]));
327	    }
328	    for cont in &desc[1..] {
329	        out.push_str(&format!("  {:<COL$}{}\n", "", cont));
330	    }
331	    out
332	}
333	
