447	/// Parse CLI args into a connection config and a command.
448	fn parse_args<I: Iterator<Item = String>>(args: I) -> Result<(Config, Command), String> {
449	    let args: Vec<String> = args.collect();
450	    if args
451	        .iter()
452	        .any(|a| matches!(a.as_str(), "help" | "--help" | "-h"))
453	    {
454	        return Ok((
455	            Config {
456	                port: String::new(),
457	                baud: 0,
458	            },
459	            Command::Help,
460	        ));
461	    }
462	
463	    let mut port = "/dev/ttyUSB0".to_string();
464	    let mut baud = 115_200u32;
465	    let mut persist = false;
466	    let mut binary = false;
467	    let mut hz: Option<u32> = None;
468	    let mut secs: Option<u64> = None;
469	    let mut fields_arg: Option<String> = None;
470	    let mut type_arg: Option<String> = None;
471	    let mut positional: Vec<String> = Vec::new();
472	
473	    let mut args = args.into_iter();
474	    while let Some(arg) = args.next() {
475	        match arg.as_str() {
476	            "--port" => port = args.next().ok_or("--port requires a value")?,
477	            "--baud" => {
478	                baud = args
479	                    .next()
480	                    .ok_or("--baud requires a value")?
481	                    .parse()
482	                    .map_err(|_| "--baud must be a number")?
483	            }
484	            "--persist" => persist = true,
485	            "--bin" => binary = true,
486	            "--hz" => {
487	                hz = Some(
488	                    args.next()
489	                        .ok_or("--hz requires a value")?
490	                        .parse()
491	                        .map_err(|_| "--hz must be a number")?,
492	                )
493	            }
494	            "--secs" => {
495	                secs = Some(
496	                    args.next()
497	                        .ok_or("--secs requires a value")?
498	                        .parse()
499	                        .map_err(|_| "--secs must be a number")?,
500	                )
501	            }
502	            "--fields" => fields_arg = Some(args.next().ok_or("--fields requires a value")?),
503	            "--type" => type_arg = Some(args.next().ok_or("--type requires a value")?),
504	            _ => positional.push(arg),
505	        }
506	    }
507	
508	    let command = match positional.first().map(String::as_str) {
509	        Some("get-hz") => {
510	            if persist {
511	                return Err("--persist only applies to `set-hz`".into());
512	            }
513	            Command::GetHz
514	        }
515	        Some("set-hz") => {
516	            let hz: u32 = positional
517	                .get(1)
518	                .ok_or("set-hz requires a frequency, e.g. `set-hz 40`")?
519	                .parse()
520	                .map_err(|_| "frequency must be a number")?;
521	            if !VALID_RATES.contains(&hz) {
522	                return Err(format!(
523	                    "{hz} Hz is not valid; choose one of {VALID_RATES:?}"
524	                ));
525	            }
526	            Command::SetHz { hz, persist }
527	        }
528	        Some("baud") => {
529	            let new_baud: u32 = positional
530	                .get(1)
531	                .ok_or("baud requires a value, e.g. `baud 921600`")?
532	                .parse()
533	                .map_err(|_| "baud must be a number")?;
534	            if !VALID_BAUDS.contains(&new_baud) {
535	                return Err(format!(
536	                    "{new_baud} is not a valid VN-100 baud; choose one of {VALID_BAUDS:?}"
537	                ));
538	            }
539	            Command::SetBaud {
540	                baud: new_baud,
541	                persist,
542	            }
543	        }
544	        Some("rrg") => {
545	            let id: u8 = positional
546	                .get(1)
547	                .ok_or("rrg requires a register id, e.g. `rrg 1`")?
548	                .parse()
549	                .map_err(|_| "register id must be 0-255")?;
550	            Command::Rrg { id }
551	        }
552	        Some("wrg") => {
553	            let id: u8 = positional
554	                .get(1)
555	                .ok_or("wrg requires a register id, e.g. `wrg 7 40`")?
556	                .parse()
557	                .map_err(|_| "register id must be 0-255")?;
558	            let params: Vec<String> = positional.iter().skip(2).cloned().collect();
559	            if params.is_empty() {
560	                return Err("wrg requires at least one value, e.g. `wrg 7 40`".into());
561	            }
562	            Command::Wrg { id, params }
563	        }
564	        Some("reset") => Command::Reset,
565	        Some("factory-reset") => Command::FactoryReset,
566	        Some("bench") => {
567	            let hz = hz.unwrap_or(40);
568	            let secs = secs.unwrap_or(5);
569	            if binary {
570	                if type_arg.is_some() {
571	                    return Err(
572	                        "--type only applies to the ASCII bench (binary picks data with --fields)"
573	                            .into(),
574	                    );
575	                }
576	                if hz == 0 || 800 % hz != 0 {
577	                    return Err(format!(
578	                        "--hz {hz} invalid for --bin; the binary rate is 800/divisor, so HZ must \
579	                         divide 800 (e.g. 50, 100, 200, 400)"
580	                    ));
581	                }
582	                let fields = match &fields_arg {
583	                    Some(list) => parse_fields(list)?,
584	                    None => default_fields(),
585	                };
586	                Command::Bench {
587	                    binary: true,
588	                    hz,
589	                    secs,
590	                    fields,
591	                    ascii_type: None,
592	                }
593	            } else {
594	                if fields_arg.is_some() {
595	                    return Err(
596	                        "--fields only applies with --bin (ASCII async uses preset messages, \
597	                         not arbitrary fields)"
598	                            .into(),
599	                    );
600	                }
601	                let ascii_type = match &type_arg {
602	                    Some(t) => Some(parse_ascii_type(t)?),
603	                    None => None,
604	                };
605	                if !VALID_RATES.contains(&hz) {
606	                    return Err(format!(
607	                        "--hz {hz} not valid for the ASCII async output; choose one of \
608	                         {VALID_RATES:?} (or use --bin)"
609	                    ));
610	                }
611	                Command::Bench {
612	                    binary: false,
613	                    hz,
614	                    secs,
615	                    fields: Vec::new(),
616	                    ascii_type,
617	                }
618	            }
619	        }
620	        Some(other) => return Err(format!("unknown command `{other}`")),
621	        None => {
622	            return Err(
623	                "missing command (`get-hz`, `set-hz`, `baud`, `rrg`, `wrg`, `bench`, `reset`, \
624	                 `factory-reset`, or `help`)"
625	                    .into(),
626	            )
627	        }
628	    };
