633	/// Read from the device until `matches` accepts a line or the deadline passes.
634	///
635	/// Reads raw bytes (not `read_line`) so a stream of garbage with no newline —
636	/// e.g. when the host baud doesn't match the device — can't block us forever:
637	/// we honor an overall `deadline` and cap line length to drop runaway junk.
638	fn read_reply<R, F>(
639	    reader: &mut R,
640	    deadline: Instant,
641	    mut matches: F,
642	) -> std::io::Result<Option<String>>
643	where
644	    R: Read,
645	    F: FnMut(&str) -> bool,
646	{
647	    let mut buf = [0u8; 256];
648	    let mut line: Vec<u8> = Vec::new();
649	    loop {
650	        if Instant::now() >= deadline {
651	            return Ok(None);
652	        }
653	        let n = match reader.read(&mut buf) {
654	            // On a serial port there is no real EOF: a read that yields nothing
655	            // (Ok(0), or a TimedOut/WouldBlock error) just means "no data within
656	            // this read window". Keep waiting — the overall `deadline` is the only
657	            // terminator, so a reply that lags (e.g. while the device reconfigures
658	            // its UART for a baud change) isn't dropped.
659	            Ok(0) => continue,
660	            Ok(n) => n,
661	            Err(ref e)
662	                if matches!(
663	                    e.kind(),
664	                    std::io::ErrorKind::TimedOut | std::io::ErrorKind::WouldBlock
665	                ) =>
666	            {
667	                continue
668	            }
669	            Err(e) => return Err(e),
670	        };
671	        for &b in &buf[..n] {
672	            match b {
673	                b'\n' => {
674	                    let raw = String::from_utf8_lossy(&line);
675	                    // An ASCII reply ($VN...*XX) can arrive with leading bytes on
676	                    // the same line — e.g. binary frames still streaming when the
677	                    // echo lands. The reply starts at the last '$', so slice there
678	                    // before matching/validating.
679	                    let candidate: String = match raw.rfind('$') {
680	                        Some(p) => raw[p..].trim().to_string(),
681	                        None => raw.trim().to_string(),
682	                    };
683	                    line.clear();
684	                    if matches(&candidate) {
685	                        return Ok(Some(candidate));
686	                    }
687	                }
688	                b'\r' => {}
689	                _ => {
690	                    line.push(b);
691	                    if line.len() > 1024 {
692	                        line.clear(); // drop a runaway (likely garbage) line
693	                    }
694	                }
695	            }
696	        }
697	    }
698	}
