700	/// Send `cmd`, wait up to `wait` for a reply matching `accept`, and validate it.
701	/// A `$VNERR` reply is surfaced as an error; a checksum mismatch is rejected.
702	fn transact<S: Read + Write>(
703	    port: &mut S,
704	    cmd: &str,
705	    wait: Duration,
706	    accept: impl Fn(&str) -> bool,
707	    missing: &str,
708	) -> Result<String, Box<dyn std::error::Error>> {
709	    print!("TX: {cmd}");
710	    port.write_all(cmd.as_bytes())?;
711	    port.flush()?;
712	
713	    let deadline = Instant::now() + wait;
714	    let reply = read_reply(port, deadline, |l| accept(l) || l.starts_with("$VNERR"))?
715	        .ok_or_else(|| missing.to_string())?;
716	    verify_checksum(&reply)?;
717	    if reply.starts_with("$VNERR") {
718	        return Err(vnerr_message(&reply).into());
719	    }
720	    Ok(reply)
721	}
