723	/// Like `transact`, but resends the command up to `attempts` times. A fresh
724	/// open (especially at high baud) can drop the first query or its reply while
725	/// the USB-serial chip locks its divisor and open-time line noise drains, so a
726	/// single shot is unreliable. A device `$VNERR` is returned immediately —
727	/// retrying a rejected command won't change the answer.
728	fn transact_retry<S: Read + Write>(
729	    port: &mut S,
730	    cmd: &str,
731	    attempts: u32,
732	    accept: impl Fn(&str) -> bool,
733	    missing: &str,
734	) -> Result<String, Box<dyn std::error::Error>> {
735	    let mut last: Option<Box<dyn std::error::Error>> = None;
736	    for attempt in 1..=attempts {
737	        match transact(
738	            port,
739	            cmd,
740	            Duration::from_millis(800),
741	            |l| accept(l),
742	            "no reply yet",
743	        ) {
744	            Ok(reply) => return Ok(reply),
745	            // A device-side error is a definitive answer; don't keep retrying it.
746	            Err(e) if e.to_string().starts_with("device error") => return Err(e),
747	            Err(e) => {
748	                last = Some(e);
749	                if attempt < attempts {
750	                    println!("  attempt {attempt}/{attempts}: no response yet, retrying...");
751	                    std::thread::sleep(Duration::from_millis(100));
752	                }
753	            }
754	        }
755	    }
756	    Err(format!(
757	        "{missing} (after {attempts} attempts; last: {})",
758	        last.map(|e| e.to_string()).unwrap_or_default()
759	    )
760	    .into())
761	}
