763	/// Send a command that causes the device to reboot ($VNRST / $VNRFS). The echo
764	/// may or may not arrive before the reset, so a missing reply is NOT an error;
765	/// only a `$VNERR` (e.g. unauthorized) is surfaced.
766	fn send_reboot_command<S: Read + Write>(
767	    port: &mut S,
768	    cmd: &str,
769	    accept: impl Fn(&str) -> bool,
770	) -> Result<(), Box<dyn std::error::Error>> {
771	    print!("TX: {cmd}");
772	    port.write_all(cmd.as_bytes())?;
773	    port.flush()?;
774	
775	    let deadline = Instant::now() + Duration::from_millis(1500);
776	    match read_reply(port, deadline, |l| accept(l) || l.starts_with("$VNERR"))? {
777	        Some(reply) if reply.starts_with("$VNERR") => Err(vnerr_message(&reply).into()),
778	        Some(reply) => {
779	            println!("RX: {reply}");
780	            Ok(())
781	        }
782	        None => {
783	            println!("(no echo — device likely rebooted before replying, which is normal)");
784	            Ok(())
785	        }
786	    }
787	}
