789	/// VectorNav 16-bit CRC (CRC-CCITT/XMODEM, the algorithm from their app note).
790	/// A valid binary packet, run from the groups byte through the trailing CRC,
791	/// produces 0. Authoritative: REFERENCE.md "Framing & checksums" (ICD §1.4).
792	fn vn_crc16(data: &[u8]) -> u16 {
793	    let mut crc: u16 = 0;
794	    for &b in data {
795	        crc = crc.rotate_left(8);
796	        crc ^= b as u16;
797	        crc ^= (crc & 0xff) >> 4;
798	        crc ^= crc << 12;
799	        crc ^= (crc & 0x00ff) << 5;
800	    }
801	    crc
802	}
803	
804	// Binary frame: sync 0xFA, groups=0x01 (Common), one 16-bit field mask, the
805	// selected fields' payload, then a 2-byte CRC. Length depends on the field set.
806	const BENCH_SYNC: u8 = 0xFA;
807	const BENCH_GROUPS: u8 = 0x01;
808	const BENCH_HEADER: usize = 1 + 1 + 2; // sync + groups + field mask
809	const BENCH_CRC: usize = 2;
810	
811	/// A measurement outcome: (count, total wire bytes, elapsed seconds, first sample).
812	type Measured = (u64, u64, f64, Option<String>);
813	
814	/// Read a little-endian f32 from `buf` at `off`.
815	fn rd_f32(buf: &[u8], off: usize) -> f32 {
816	    f32::from_le_bytes(buf[off..off + 4].try_into().unwrap())
817	}
818	
819	/// Human-readable decode of the selected fields in one binary frame.
820	fn decode_binary_sample(frame: &[u8], fields: &[&Field]) -> String {
821	    let mut off = BENCH_HEADER;
822	    let mut parts = Vec::new();
823	    for f in fields {
824	        let s = match f.name {
825	            "time" => format!(
826	                "t={} ns",
827	                u64::from_le_bytes(frame[off..off + 8].try_into().unwrap())
828	            ),
829	            "ypr" => format!(
830	                "ypr=[{:.2}, {:.2}, {:.2}] deg",
831	                rd_f32(frame, off),
832	                rd_f32(frame, off + 4),
833	                rd_f32(frame, off + 8)
834	            ),
835	            "quat" => format!(
836	                "quat=[{:.4}, {:.4}, {:.4}, {:.4}]",
837	                rd_f32(frame, off),
838	                rd_f32(frame, off + 4),
839	                rd_f32(frame, off + 8),
840	                rd_f32(frame, off + 12)
841	            ),
842	            "gyro" => format!(
843	                "gyro=[{:.4}, {:.4}, {:.4}] rad/s",
844	                rd_f32(frame, off),
845	                rd_f32(frame, off + 4),
846	                rd_f32(frame, off + 8)
847	            ),
848	            "accel" => format!(
849	                "accel=[{:.3}, {:.3}, {:.3}] m/s^2",
850	                rd_f32(frame, off),
851	                rd_f32(frame, off + 4),
852	                rd_f32(frame, off + 8)
853	            ),
854	            "imu" => format!(
855	                "uncomp_accel=[{:.3}, {:.3}, {:.3}] uncomp_gyro=[{:.4}, {:.4}, {:.4}]",
856	                rd_f32(frame, off),
857	                rd_f32(frame, off + 4),
858	                rd_f32(frame, off + 8),
859	                rd_f32(frame, off + 12),
860	                rd_f32(frame, off + 16),
861	                rd_f32(frame, off + 20)
862	            ),
863	            "magpres" => format!(
864	                "mag=[{:.3}, {:.3}, {:.3}] G temp={:.2} C pres={:.3} kPa",
865	                rd_f32(frame, off),
866	                rd_f32(frame, off + 4),
867	                rd_f32(frame, off + 8),
868	                rd_f32(frame, off + 12),
869	                rd_f32(frame, off + 16)
870	            ),
871	            _ => "?".to_string(),
872	        };
873	        parts.push(s);
874	        off += f.size;
875	    }
876	    parts.join(", ")
877	}
