879	/// Measure binary frames of `frame_len` bytes for `secs`. Counts CRC-valid
880	/// frames and captures the first frame's raw bytes for the caller to decode.
881	fn measure_binary<S: Read>(
882	    port: &mut S,
883	    frame_len: usize,
884	    secs: u64,
885	) -> std::io::Result<(u64, u64, f64, Option<Vec<u8>>)> {
886	    let start = Instant::now();
887	    let deadline = start + Duration::from_secs(secs);
888	    let mut buf = [0u8; 1024];
889	    let mut acc: Vec<u8> = Vec::new();
890	    let mut frames = 0u64;
891	    let mut first: Option<Vec<u8>> = None;
892	
893	    while Instant::now() < deadline {
894	        match port.read(&mut buf) {
895	            Ok(0) => continue,
896	            Ok(n) => acc.extend_from_slice(&buf[..n]),
897	            Err(ref e)
898	                if matches!(
899	                    e.kind(),
900	                    std::io::ErrorKind::TimedOut | std::io::ErrorKind::WouldBlock
901	                ) =>
902	            {
903	                continue
904	            }
905	            Err(e) => return Err(e),
906	        }
907	
908	        let mut i = 0;
909	        while i + frame_len <= acc.len() {
910	            if acc[i] != BENCH_SYNC || acc[i + 1] != BENCH_GROUPS {
911	                i += 1;
912	                continue;
913	            }
914	            let frame = &acc[i..i + frame_len];
915	            // CRC over everything after the sync byte (groups..payload..crc) == 0.
916	            if vn_crc16(&frame[1..]) == 0 {
917	                frames += 1;
918	                if first.is_none() {
919	                    first = Some(frame.to_vec());
920	                }
921	                i += frame_len;
922	            } else {
923	                i += 1; // false sync (0xFA can appear in payload); resync
924	            }
925	        }
926	        acc.drain(0..i);
927	        if acc.len() > 8192 {
928	            let keep = acc.len() - frame_len;
929	            acc.drain(0..keep);
930	        }
931	    }
932	
933	    Ok((
934	        frames,
935	        frames * frame_len as u64,
936	        start.elapsed().as_secs_f64(),
937	        first,
938	    ))
939	}
