941	/// True if `line` is an async data message (a `$VN...` line that isn't a command
942	/// echo or error) with a valid checksum.
943	fn is_async_line(line: &str) -> bool {
944	    line.starts_with("$VN")
945	        && !line.starts_with("$VNRRG")
946	        && !line.starts_with("$VNWRG")
947	        && !line.starts_with("$VNERR")
948	        && verify_checksum(line).is_ok()
949	}
