951	/// Measure ASCII async messages for `secs`: counts valid `$VN...` lines and
952	/// their wire bytes, capturing the first as the sample.
953	fn measure_ascii<S: Read>(port: &mut S, secs: u64) -> std::io::Result<Measured> {
954	    let start = Instant::now();
955	    let deadline = start + Duration::from_secs(secs);
956	    let mut buf = [0u8; 1024];
957	    let mut line: Vec<u8> = Vec::new();
958	    let mut msgs = 0u64;
959	    let mut bytes = 0u64;
960	    let mut sample = None;
961	
962	    while Instant::now() < deadline {
963	        let n = match port.read(&mut buf) {
964	            Ok(0) => continue,
965	            Ok(n) => n,
966	            Err(ref e)
967	                if matches!(
968	                    e.kind(),
969	                    std::io::ErrorKind::TimedOut | std::io::ErrorKind::WouldBlock
970	                ) =>
971	            {
972	                continue
973	            }
974	            Err(e) => return Err(e),
975	        };
976	        for &b in &buf[..n] {
977	            match b {
978	                b'\n' => {
979	                    let raw = String::from_utf8_lossy(&line);
980	                    let cand = match raw.rfind('$') {
981	                        Some(p) => raw[p..].trim(),
982	                        None => raw.trim(),
983	                    };
984	                    if is_async_line(cand) {
985	                        msgs += 1;
986	                        bytes += cand.len() as u64 + 2; // + CRLF
987	                        if sample.is_none() {
988	                            sample = Some(cand.to_string());
989	                        }
990	                    }
991	                    line.clear();
992	                }
993	                b'\r' => {}
994	                _ => {
995	                    line.push(b);
996	                    if line.len() > 1024 {
997	                        line.clear();
998	                    }
999	                }
1000	            }
1001	        }
1002	    }
1003	
1004	    Ok((msgs, bytes, start.elapsed().as_secs_f64(), sample))
1005	}
