1007	/// Print the shared bench result block (rate, sample, wire utilization).
1008	fn report_bench(unit: &str, target_hz: u32, m: Measured, baud: u32) {
1009	    let (count, bytes, elapsed, sample) = m;
1010	    let rate = if elapsed > 0.0 {
1011	        count as f64 / elapsed
1012	    } else {
1013	        0.0
1014	    };
1015	    println!("\nResult: {count} {unit} in {elapsed:.2}s = {rate:.1} Hz (target {target_hz} Hz).");
1016	    if let Some(s) = sample {
1017	        println!("Sample: {s}");
1018	    }
1019	    let bits = if elapsed > 0.0 {
1020	        bytes as f64 * 10.0 / elapsed
1021	    } else {
1022	        0.0
1023	    };
1024	    let pct = 100.0 * bits / baud as f64;
1025	    println!(
1026	        "Wire throughput ~{:.0} kbit/s = {:.0}% of the {:.1} kbit/s {baud}-baud link.",
1027	        bits / 1000.0,
1028	        pct,
1029	        baud as f64 / 1000.0
1030	    );
1031	}
