1033	/// Configure a binary output (reg 75) with `fields` at `hz`, measure the frame
1034	/// rate for `secs`, then restore the prior state.
1035	fn bench_binary<S: Read + Write>(
1036	    port: &mut S,
1037	    baud: u32,
1038	    hz: u32,
1039	    secs: u64,
1040	    fields: &[&Field],
1041	) -> Result<(), Box<dyn std::error::Error>> {
1042	    let divisor = 800 / hz; // device IMU base rate is 800 Hz
1043	    let mask: u16 = fields.iter().fold(0, |m, f| m | (1u16 << f.bit));
1044	    let payload: usize = fields.iter().map(|f| f.size).sum();
1045	    let frame_len = BENCH_HEADER + payload + BENCH_CRC;
1046	    let names: Vec<&str> = fields.iter().map(|f| f.name).collect();
1047	
1048	    // Remember the current ASCII async rate so we can put it back.
1049	    let prev = transact_retry(
1050	        port,
1051	        &build_command("VNRRG,07"),
1052	        5,
1053	        |l| parse_reg07(l).is_some(),
1054	        "could not read current async rate",
1055	    )?;
1056	    let prev_hz = parse_reg07(&prev).unwrap();
1057	
1058	    // Configure Binary Output 1 (reg 75) on serial1. A $VNERR here means the
1059	    // chosen fields+rate don't fit the current baud — nothing else has changed.
1060	    let cfg = format!("VNWRG,75,1,{divisor},01,{mask:04X}");
1061	    transact_retry(
1062	        port,
1063	        &build_command(&cfg),
1064	        5,
1065	        |l| l.starts_with("$VNWRG,75"),
1066	        "device did not accept the binary config (a $VNERR means it won't fit at this baud)",
1067	    )?;
1068	    println!(
1069	        "Configured binary output: Common{names:?} @ {hz} Hz (divisor {divisor}, {frame_len} B/frame)."
1070	    );
1071	
1072	    // Silence the ASCII async output so we measure ONLY the binary stream.
1073	    transact_retry(
1074	        port,
1075	        &build_command("VNWRG,07,0"),
1076	        5,
1077	        |l| parse_reg07(l).is_some(),
1078	        "could not disable ASCII async output",
1079	    )?;
1080	
1081	    println!("Measuring for {secs}s...");
1082	    let (frames, bytes, elapsed, first) = measure_binary(port, frame_len, secs)?;
1083	    let sample = first.map(|fr| decode_binary_sample(&fr, fields));
1084	    report_bench("frames", hz, (frames, bytes, elapsed, sample), baud);
1085	
1086	    // Restore: turn the binary output off, put the ASCII rate back.
1087	    let _ = transact_retry(
1088	        port,
1089	        &build_command(&format!("VNWRG,75,0,{divisor},01,{mask:04X}")),
1090	        3,
1091	        |l| l.starts_with("$VNWRG,75"),
1092	        "restore: disable binary output",
1093	    );
1094	    let _ = transact_retry(
1095	        port,
1096	        &build_command(&format!("VNWRG,07,{prev_hz}")),
1097	        3,
1098	        |l| parse_reg07(l).is_some(),
1099	        "restore: ASCII async rate",
1100	    );
1101	    println!("Restored: binary output off, ASCII async back to {prev_hz} Hz.");
1102	
1103	    if frames == 0 {
1104	        return Err(
1105	            "received 0 binary frames — the config may have targeted the wrong serial port \
1106	             (try a VN-100 on serial1), or the device isn't streaming"
1107	                .into(),
1108	        );
1109	    }
1110	    Ok(())
1111	}
