1201	/// Print the fields of a `$VN(R|W)RG,<id>,<f1>,<f2>...*XX` reply.
1202	fn print_reg_fields(reply: &str) {
1203	    let body = reply.trim_start_matches('$');
1204	    let body = body.split('*').next().unwrap_or(body);
1205	    let parts: Vec<&str> = body.split(',').collect();
1206	    match parts.as_slice() {
1207	        [_, id, fields @ ..] if !fields.is_empty() => {
1208	            println!("register {id}: {fields:?}");
1209	        }
1210	        [_, id] => println!("register {id}: (no fields)"),
1211	        _ => println!("(unrecognized reply)"),
1212	    }
1213	}
