1215	fn main() -> Result<(), Box<dyn std::error::Error>> {
1216	    let (config, command) = match parse_args(std::env::args().skip(1)) {
1217	        Ok(parsed) => parsed,
1218	        Err(e) => {
1219	            eprintln!("error: {e}\n");
1220	            eprint!("{}", help_text());
1221	            std::process::exit(2);
1222	        }
1223	    };
1224	
1225	    if let Command::Help = command {
1226	        print!("{}", help_text());
1227	        return Ok(());
1228	    }
1229	
1230	    println!("Opening {} at {} baud...", config.port, config.baud);
1231	    let mut port = serialport::new(&config.port, config.baud)
1232	        // Short per-read timeout so read_reply re-checks its overall deadline often.
1233	        .timeout(Duration::from_millis(250))
1234	        .open()?;
1235	
1236	    // Let the USB-serial chip lock its baud divisor, then drop any open-time
1237	    // line noise / partial async frame before the first command. Without this,
1238	    // a fresh open at high baud often loses its first query.
1239	    std::thread::sleep(Duration::from_millis(150));
1240	    let _ = port.clear(serialport::ClearBuffer::Input);
1241	
1242	    // Shared "we heard nothing usable" hint — usually a baud mismatch.
1243	    let no_reply = format!(
1244	        "no usable reply from device — is it actually at {} baud? \
1245	         (VN-100 factory default is 115200; use --baud to match, or the `baud` command to change it)",
1246	        config.baud
1247	    );
1248	
1249	    match command {
1250	        Command::Help => unreachable!("handled above"),
1251	
1252	        Command::GetHz => {
1253	            let reply = transact_retry(
1254	                &mut port,
1255	                &build_command("VNRRG,07"),
1256	                5,
1257	                |l| parse_reg07(l).is_some(),
1258	                &no_reply,
1259	            )?;
1260	            println!("RX: {reply}");
1261	            println!("Async output rate: {} Hz", parse_reg07(&reply).unwrap());
1262	        }
1263	
1264	        Command::SetHz { hz, persist } => {
1265	            let reply = transact_retry(
1266	                &mut port,
1267	                &build_command(&format!("VNWRG,07,{hz}")),
1268	                5,
1269	                |l| parse_reg07(l).is_some(),
1270	                &no_reply,
1271	            )?;
1272	            println!("RX: {reply}");
1273	            println!("Async output rate: {} Hz", parse_reg07(&reply).unwrap());
1274	
1275	            if persist {
1276	                let confirm = transact_retry(
1277	                    &mut port,
1278	                    &build_command("VNWNV"),
1279	                    5,
1280	                    |l| l.starts_with("$VNWNV"),
1281	                    &no_reply,
1282	                )?;
1283	                println!("RX: {confirm}");
1284	                println!("Settings written to non-volatile memory.");
1285	            }
1286	        }
1287	
1288	        Command::SetBaud {
1289	            baud: new_baud,
1290	            persist,
1291	        } => {
1292	            // The device replies at the CURRENT baud, then switches to the new one.
1293	            let reply = transact_retry(
1294	                &mut port,
1295	                &build_command(&format!("VNWRG,05,{new_baud}")),
1296	                5,
1297	                |l| l.starts_with("$VNWRG,05,"),
1298	                &no_reply,
1299	            )?;
1300	            println!("RX: {reply}");
1301	            println!("Device acknowledged baud change to {new_baud}.");
1302	
1303	            // Give the device a moment to reconfigure its UART before we talk at
1304	            // the new rate (the vendor SDK waits ~50 ms here), then switch THIS
1305	            // connection in place. We switch in-session rather than close/reopen
1306	            // not because the device would forget the baud — it holds the RAM
1307	            // value across host reconnects — but because each reconnect risks a
1308	            // line transient that, at very high baud (e.g. 921600 on an FT232R),
1309	            // can wedge the link until a power cycle.
1310	            std::thread::sleep(Duration::from_millis(60));
1311	            port.set_baud_rate(new_baud)?;
1312	            // Drop any bytes that were in flight across the switch.
1313	            let _ = port.clear(serialport::ClearBuffer::Input);
1314	
1315	            println!("Verifying at {new_baud} baud...");
1316	            let verify = transact_retry(
1317	                &mut port,
1318	                &build_command("VNRRG,07"),
1319	                5,
1320	                |l| parse_reg07(l).is_some(),
1321	                "device did not respond at the new baud (a power cycle reverts to the flash baud)",
1322	            )?;
1323	            println!("RX: {verify}");
1324	            println!(
1325	                "Verified — device is at {new_baud} baud (async rate {} Hz).",
1326	                parse_reg07(&verify).unwrap()
1327	            );
1328	
1329	            if persist {
1330	                let confirm = transact_retry(
1331	                    &mut port,
1332	                    &build_command("VNWNV"),
1333	                    5,
1334	                    |l| l.starts_with("$VNWNV"),
1335	                    "no $VNWNV confirmation at the new baud",
1336	                )?;
1337	                println!("RX: {confirm}");
1338	                println!("Baud saved to flash; the device will boot at {new_baud} from now on.");
1339	            } else {
1340	                println!(
1341	                    "(Volatile — the device holds this across host reconnects, but a \
1342	                     power cycle or `reset`/`factory-reset` reverts it to the flash baud. \
1343	                     Re-run with `baud {new_baud} --persist` to make it permanent.)"
1344	                );
1345	            }
1346	        }
1347	
1348	        Command::Reset => {
1349	            send_reboot_command(&mut port, &build_command("VNRST"), |l| {
1350	                l.starts_with("$VNRST")
1351	            })?;
1352	            println!("Reset requested — sensor is rebooting and reloading its saved settings.");
1353	        }
1354	
1355	        Command::Rrg { id } => {
1356	            let reply = transact_retry(
1357	                &mut port,
1358	                &build_command(&format!("VNRRG,{id:02}")),
1359	                5,
1360	                |l| l.starts_with("$VNRRG,"),
1361	                &no_reply,
1362	            )?;
1363	            println!("RX: {reply}");
1364	            print_reg_fields(&reply);
1365	        }
1366	
1367	        Command::Wrg { id, params } => {
1368	            let payload = format!("VNWRG,{id:02},{}", params.join(","));
1369	            let reply = transact_retry(
1370	                &mut port,
1371	                &build_command(&payload),
1372	                5,
1373	                |l| l.starts_with("$VNWRG,"),
1374	                &no_reply,
1375	            )?;
1376	            println!("RX: {reply}");
1377	            print_reg_fields(&reply);
1378	        }
1379	
1380	        Command::Bench {
1381	            binary,
1382	            hz,
1383	            secs,
1384	            fields,
1385	            ascii_type,
1386	        } => {
1387	            if binary {
1388	                bench_binary(&mut port, config.baud, hz, secs, &fields)?;
1389	            } else {
1390	                bench_ascii(&mut port, config.baud, hz, secs, ascii_type)?;
1391	            }
1392	        }
1393	
1394	        Command::FactoryReset => {
1395	            println!("Restoring factory defaults — this overwrites flash and cannot be undone.");
1396	            send_reboot_command(&mut port, &build_command("VNRFS"), |l| {
1397	                l.starts_with("$VNRFS")
1398	            })?;
1399	            println!("Factory restore requested — sensor is rebooting.");
1400	            println!(
1401	                "It is now at 115200 baud with the default async output. \
1402	                 Reconnect with the default --baud (115200)."
1403	            );
1404	        }
1405	    }
1406	
1407	    Ok(())
1408	}
