1	//! `rdwr_vn100` — read and configure a VectorNav VN-100 IMU over serial.
2	//!
3	//! The VN-100 speaks an ASCII protocol over a serial port. Each command is
4	//!
5	//!     $<payload>*XX\r\n
6	//!
7	//! where `XX` is the 8-bit XOR checksum of every character of `<payload>`
8	//! (i.e. everything between `$` and `*`). Replies echo the same form; binary
9	//! outputs (register 75) use a packed frame ending in a 16-bit CRC instead.
10	//!
11	//! Commands implemented here:
12	//!   get-hz / set-hz       read/write the async output rate    (register 7)
13	//!   baud                  change the serial baud rate          (register 5)
14	//!   rrg / wrg             generic read/write of any register   ($VNRRG / $VNWRG)
15	//!   bench                 configure an output (ASCII async by default, or a
16	//!                         binary output with --bin) and measure the achieved
17	//!                         rate, to see what fits a given baud
18	//!   reset / factory-reset reboot / restore defaults            ($VNRST / $VNRFS)
19	//!
20	//! Key VN messages:
21	//!   $VNRRG,<id>*XX          -> $VNRRG,<id>,<f1>,...*YY   (read register)
22	//!   $VNWRG,<id>,<f1>,...*XX  -> echo                     (write register)
23	//!   $VNWNV*XX               -> $VNWNV*YY                 (save all to flash)
24	//!   $VNERR,<code>*XX                                     (error; see error_description)
25	//!
26	//! The async output rate (register 7) is one of a fixed firmware set
27	//! (`VALID_RATES`); a value that's out of range — or too much data for the
28	//! current baud — returns a `$VNERR` (0x0C = insufficient baud rate).
29	//!
30	//! Register/enum/table values are cited to the ICD and vnsdk in REFERENCE.md.
31	
32	use std::io::{Read, Write};
33	use std::time::{Duration, Instant};
34	
35	/// Frequencies (Hz) the VN-100 accepts for the async data output rate.
36	/// Authoritative: REFERENCE.md "Register 7" (ICD Reg 7; vnsdk AsyncOutputFreq::Adof).
37	const VALID_RATES: &[u32] = &[1, 2, 4, 5, 10, 20, 25, 40, 50, 100, 200];
38	
39	/// Serial baud rates the VN-100 supports (register 5).
40	/// Authoritative: REFERENCE.md "Register 5" (ICD Reg 5; vnsdk BaudRate::BaudRates).
41	const VALID_BAUDS: &[u32] = &[
42	    9600, 19200, 38400, 57600, 115200, 128000, 230400, 460800, 921600,
43	];
44	
45	/// A selectable binary-output field (all from the "Common" group, group 1):
46	/// CLI name, the group-1 bit it occupies, and its on-wire byte size.
47	struct Field {
48	    name: &'static str,
49	    bit: u8,
50	    size: usize,
51	}
52	
53	/// The `--fields` vocabulary (Common group only — keeps the frame to one group).
54	/// Authoritative: REFERENCE.md "Common Group" (ICD §2.2 Table 2.3).
55	const FIELDS: &[Field] = &[
56	    Field {
57	        name: "time",
58	        bit: 0,
59	        size: 8,
60	    }, // TimeStartup, u64 ns
61	    Field {
62	        name: "ypr",
63	        bit: 3,
64	        size: 12,
65	    }, // YawPitchRoll, 3×f32 deg
66	    Field {
67	        name: "quat",
68	        bit: 4,
69	        size: 16,
70	    }, // Quaternion, 4×f32
71	    Field {
72	        name: "gyro",
73	        bit: 5,
74	        size: 12,
75	    }, // AngularRate, 3×f32 rad/s
76	    Field {
77	        name: "accel",
78	        bit: 8,
79	        size: 12,
80	    }, // Accel, 3×f32 m/s^2
81	    Field {
82	        name: "imu",
83	        bit: 9,
84	        size: 24,
85	    }, // uncomp Accel+Gyro, 6×f32
86	    Field {
87	        name: "magpres",
88	        bit: 10,
89	        size: 20,
90	    }, // Mag(3×f32)+Temp+Pres
91	];
92	
93	fn lookup_field(name: &str) -> Option<&'static Field> {
94	    FIELDS.iter().find(|f| f.name == name)
95	}
96	
97	fn field_names() -> String {
98	    FIELDS.iter().map(|f| f.name).collect::<Vec<_>>().join(", ")
99	}
100	
101	/// Parse a comma-separated `--fields` list into Common-group fields, ordered by
102	/// bit (the order the device emits them), de-duplicated.
103	fn parse_fields(list: &str) -> Result<Vec<&'static Field>, String> {
104	    let mut out: Vec<&'static Field> = Vec::new();
105	    for name in list.split(',').map(str::trim).filter(|s| !s.is_empty()) {
106	        let f = lookup_field(name)
107	            .ok_or_else(|| format!("unknown field `{name}`; choose from {}", field_names()))?;
108	        if !out.iter().any(|g| g.name == f.name) {
109	            out.push(f);
110	        }
111	    }
112	    if out.is_empty() {
113	        return Err("--fields needs at least one field".into());
114	    }
115	    out.sort_by_key(|f| f.bit);
116	    Ok(out)
117	}
118	
119	/// Default binary field set: timestamp + acceleration.
120	fn default_fields() -> Vec<&'static Field> {
121	    vec![
122	        lookup_field("time").unwrap(),
123	        lookup_field("accel").unwrap(),
124	    ]
125	}
126	
127	/// Compute the VN-100 checksum: XOR of all bytes in `payload`.
128	fn checksum(payload: &str) -> u8 {
129	    payload.bytes().fold(0u8, |acc, b| acc ^ b)
130	}
131	
132	/// Build a full command line (including `$`, `*`, checksum and CRLF) from the
133	/// payload that sits between `$` and `*`, e.g. `"VNRRG,07"`.
134	fn build_command(payload: &str) -> String {
135	    format!("${}*{:02X}\r\n", payload, checksum(payload))
136	}
137	
138	/// Verify the trailing `*XX` checksum of a received `$...*XX` line.
139	fn verify_checksum(line: &str) -> Result<(), String> {
140	    let payload = line.strip_prefix('$').ok_or("reply missing leading '$'")?;
141	    let (payload, sum) = payload
142	        .rsplit_once('*')
143	        .ok_or("reply missing '*' checksum delimiter")?;
144	    let given = u8::from_str_radix(sum.trim(), 16)
145	        .map_err(|_| format!("malformed checksum field {sum:?}"))?;
146	    let actual = checksum(payload);
147	    if given == actual {
148	        Ok(())
149	    } else {
150	        Err(format!(
151	            "checksum mismatch: reply says {given:02X}, computed {actual:02X}"
152	        ))
153	    }
154	}
155	
156	/// Human-readable description of a VN-100 system error code.
157	/// Authoritative: REFERENCE.md "Error responses" (ICD §1; vnsdk Errors.hpp Error).
158	fn error_description(code: u8) -> &'static str {
159	    match code {
160	        1 => "hard fault",
161	        2 => "serial buffer overflow",
162	        3 => "invalid checksum",
163	        4 => "invalid command",
164	        5 => "not enough parameters",
165	        6 => "too many parameters",
166	        7 => "invalid parameter",
167	        8 => "invalid register",
168	        9 => "unauthorized access",
169	        10 => "watchdog reset",
170	        11 => "output buffer overflow",
171	        12 => "insufficient baud rate",
172	        255 => "error buffer overflow",
173	        _ => "unknown error",
174	    }
175	}
176	
177	/// Turn a `$VNERR,<code>*XX` line into a readable message. The code is hex.
178	fn vnerr_message(line: &str) -> String {
179	    let code = line
180	        .strip_prefix("$VNERR,")
181	        .and_then(|b| b.split('*').next())
182	        .map(str::trim)
183	        .and_then(|c| u8::from_str_radix(c, 16).ok());
184	    match code {
185	        Some(n) => {
186	            let mut msg = format!("device error 0x{n:02X} ({n}): {}", error_description(n));
187	            if n == 12 {
188	                // By far the most likely error when setting a high output rate.
189	                msg.push_str(
190	                    " — the configured async message won't fit at this output rate over the \
191	                     current serial baud; raise the baud (e.g. `baud 921600`) or shorten the \
192	                     async message (register 6)",
193	                );
194	            }
195	            msg
196	        }
197	        None => format!("device error: {line}"),
198	    }
199	}
200	
201	/// Parse the rate out of a `$VN(R|W)RG,07,<freq>*XX` response line.
202	/// Returns `None` for any other (e.g. async) line.
203	fn parse_reg07(line: &str) -> Option<u32> {
204	    let body = line
205	        .strip_prefix("$VNRRG,07,")
206	        .or_else(|| line.strip_prefix("$VNWRG,07,"))?;
207	    let freq = body.split('*').next()?;
208	    freq.trim().parse().ok()
209	}
